import time
from agno import Agent

def profile_agent_latency(agent, test_inputs, threshold_ms=2000):
    latencies = []
    for input_data in test_inputs:
        start = time.perf_counter()
        result = agent.run(input_data)
        latency_ms = (time.perf_counter() - start) * 1000
        latencies.append({
            'input': input_data,
            'latency_ms': latency_ms,
            'timeout': latency_ms > threshold_ms
        })
    avg_latency = sum(l['latency_ms'] for l in latencies) / len(latencies)
    return {
        'average_latency_ms': avg_latency,
        'timeout_rate': sum(l['timeout'] for l in latencies) / len(latencies),
        'details': latencies
    }

from agno import Agent
import time

def analyze_tool_latencies(agent, test_cases):
    tool_times = {}

    def latency_wrapper(func):
        def wrapper(*args, **kwargs):
            start = time.perf_counter()
            result = func(*args, **kwargs)
            latency = (time.perf_counter() - start) * 1000
            tool_times[func.__name__] = tool_times.get(func.__name__, []) + [latency]
            return result
        return wrapper

    # Monkey patch agent tools
    for tool in agent.tools:
        tool._run = latency_wrapper(tool._run)

    for case in test_cases:
        agent.run(case)

    return {name: {'avg_ms': sum(times)/len(times), 'samples': len(times)} 
            for name, times in tool_times.items()}

